/**
 * ThemeContext
 * 
 * This file creates a React context for theme management.
 * It provides a context provider and a useTheme hook for consuming components.
 */

import React, { createContext, useState, useEffect, useContext } from 'react';
import ThemeManager from '../services/ThemeManager';

// Create context with default values
export const ThemeContext = createContext({
  theme: 'light',
  setTheme: () => {},
  themes: [],
  toggleTheme: () => {},
  themePreferences: {
    detectSystemTheme: true,
    fallbackTheme: 'dark',
    enableAnimations: true,
    reducedMotion: false,
    transitionSpeed: 300
  },
  setThemePreferences: () => {},
});

/**
 * Theme Provider Component
 * Provides theme context to all children components
 */
export const ThemeProvider = ({ children }) => {
  const [theme, setTheme] = useState('light');
  const [themePreferences, setThemePreferences] = useState({
    detectSystemTheme: true,
    fallbackTheme: 'dark',
    enableAnimations: true,
    reducedMotion: false,
    transitionSpeed: 300
  });

  // Initialize theme on mount
  useEffect(() => {
    // Get theme from localStorage or system preference
    const savedTheme = localStorage.getItem('theme-preference') || 
                       (window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light');
    
    setTheme(savedTheme);
    document.documentElement.setAttribute('data-theme', savedTheme);
    
    // Initialize the ThemeManager
    ThemeManager.initialize();
    
    // Listen for theme changes from ThemeManager
    const handleThemeChange = (data) => {
      const themeData = ThemeManager.getCurrentTheme();
      setTheme(themeData.variant);
      document.documentElement.setAttribute('data-theme', themeData.variant);
    };
    
    ThemeManager.on('themeChanged', handleThemeChange);
    
    // Cleanup
    return () => {
      ThemeManager.off('themeChanged', handleThemeChange);
    };
  }, []);
  
  // Toggle between light and dark themes
  const toggleTheme = () => {
    const newTheme = theme === 'light' ? 'dark' : 'light';
    setTheme(newTheme);
    localStorage.setItem('theme-preference', newTheme);
    document.documentElement.setAttribute('data-theme', newTheme);
    
    // Use ThemeManager to toggle theme
    ThemeManager.toggleTheme();
  };
  
  // Get all available themes
  const themes = ThemeManager.getAvailableThemes();

  // Context value
  const contextValue = {
    theme,
    setTheme,
    themes,
    toggleTheme,
    themePreferences,
    setThemePreferences
  };

  return (
    <ThemeContext.Provider value={contextValue}>
      {children}
    </ThemeContext.Provider>
  );
};

/**
 * Custom hook to use theme context
 * @returns {Object} Theme context
 */
export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (context === undefined) {
    throw new Error('useTheme must be used within a ThemeProvider');
  }
  return context;
};

export default ThemeContext;
